    "FILO": "First In, Last Out", "LCL": "Less than Container Load", "FCL": "Full Container Load",
    "MILT": "Mean Idle Time", "OTM": "Operador de Transporte Multimodal", "OTD": "On-Time Delivery",
    "OTIF": "On-Time In-Full", "SOP": "Sales and Operations Planning", "CPFR": "Collaborative Planning, Forecasting, and Replenishment",
