    "BIOS": "Sistema Básico de Entrada e Saída", "UEFI": "Interface de Firmware Extensível Unificada",
    "FAT32": "Tabela de Alocação de Arquivos 32", "NTFS": "Sistema de Arquivos de Nova Tecnologia",
    "EXT4": "Quarto Sistema de Arquivos Estendido", "IIS": "Serviços de Informação de Internet",
    "SGBD": "Sistema de Gerenciamento de Banco de Dados", "NoSQL": "Não Apenas SQL",
    "ODBC": "Conectividade Aberta de Banco de Dados", "JDBC": "Conectividade de Banco de Dados Java",
    "OLAP": "Processamento Analítico Online", "OLTP": "Processamento de Transação Online",
    "RESTful": "Serviços Web de Transferência de Estado Representativo", "SOAP": "Protocolo de Acesso a Objetos Simples",
