    "CSV": "Valores Separados por Vírgula", "XLSX": "Planilha XML Aberta do Excel",
    "DOCX": "Documento XML Aberto do Word", "PPTX": "Apresentação XML Aberta do PowerPoint",
    "ZIP": "Arquivo Compactado ZIP", "RAR": "Arquivo Compactado RAR", "TAR": "Arquivo de Fita Unificado",
