    "NOC": "Centro de Operações de Rede", "SOC": "Centro de Operações de Segurança",
    "SIEM": "Gerenciamento de Informações e Eventos de Segurança", "IAM": "Gestão de Identidade e Acesso",
    "SSO": "Autenticação Única", "MFA": "Autenticação Multifator", "2FA": "Autenticação de Dois Fatores",
    "OTP": "Senha de Uso Único", "RBAC": "Controle de Acesso Baseado em Funções", "ABAC": "Controle de Acesso Baseado em Atributos",
    "LDAP": "Protocolo Leve de Acesso a Diretórios", "AD": "Diretório Ativo", "SMB": "Bloqueio de Mensagens do Servidor",
    "DHCP": "Protocolo de Configuração Dinâmica de Host", "SMTP": "Protocolo de Transferência de Correio Simples",
    "IMAP": "Protocolo de Acesso ao Correio da Internet", "POP3": "Protocolo de Correio de Agência Postal 3",
    "SNMP": "Protocolo Simples de Gerenciamento de Rede", "NTP": "Protocolo de Tempo de Rede",
